select

from plant_experiment_detail_tb

    and pd_num=#{pdNum,jdbcType=VARCHAR}
    and experiment_num=#{experimentNum,jdbcType=VARCHAR}
    and region_num=#{regionNum,jdbcType=VARCHAR}
    and vector_task_code=#{vectorTaskCode,jdbcType=VARCHAR}
    and seed_num=#{seedNum,jdbcType=VARCHAR}
    and breed_code=#{breedCode,jdbcType=VARCHAR}
    and plant_code=#{plantCode,jdbcType=VARCHAR},
    and generation_code=#{generationCode,jdbcType=VARCHAR}
    and species_code=#{speciesCode,jdbcType=VARCHAR}
    and plant_time=#{plantTime,jdbcType=VARCHAR}
    and plant_number=#{plantNumber,jdbcType=NUMERIC}

        and   experiment_address_code=#{experimentAddressCode,jdbcType=VARCHAR}

    and plant_unit=#{plantUnit,jdbcType=VARCHAR}
    and remarks=#{remarks,jdbcType=VARCHAR}
    and gene_type=#{geneType,jdbcType=VARCHAR}
    and create_user_id=#{createUserId,jdbcType=NUMERIC}
    and create_user_name=#{createUserName,jdbcType=VARCHAR}
    and create_time=#{createTime,jdbcType=TIMESTAMP}
